{
  "query": "query GetHSKWords($level: Int!, $limit: Int!) {
    wordsByHSK(level: $level, limit: $limit) {
      id
      hanzi
      traditional
      pinyin
      meanings
      hskLevel
      frequency
    }
  }",
  "variables": {
    "level": 1,
    "limit": 10
  }
}

{
  "query": "query SearchWords($query: String!, $limit: Int!) {
    searchWords(query: $query, limit: $limit) {
      id
      hanzi
      traditional
      pinyin
      meanings
      hskLevel
    }
  }",
  "variables": {
    "query": "好",
    "limit": 5
  }
}

{
  "query": "query GetWord($hanzi: String!) {
    word(hanzi: $hanzi) {
      id
      hanzi
      traditional
      pinyin
      meanings
      hskLevel
      frequency
      compounds {
        word {
          hanzi
          pinyin
          meanings
        }
        relationshipType
        meaning
        phrase
        usageExample
      }
      phrases {
        word {
          hanzi
          pinyin
        }
        relationshipType
        meaning
        phrase
      }
    }
  }",
  "variables": {
    "hanzi": "好"
  }
}

{
  "query": "query GetWordGraph($hanzi: String!, $depth: Int!, $maxNodes: Int!) {
    wordGraph(hanzi: $hanzi, depth: $depth, maxNodes: $maxNodes) {
      centerWord {
        id
        hanzi
        pinyin
        meanings
      }
      nodes {
        id
        word {
          hanzi
          pinyin
          meanings
        }
        distance
        importance
      }
      edges {
        id
        source
        target
        type
        label
        weight
        bidirectional
      }
      depth
    }
  }",
  "variables": {
    "hanzi": "好",
    "depth": 2,
    "maxNodes": 15
  }
}

{
  "query": "query GetDailyWords($count: Int!, $hskLevel: Int) {
    dailyWords(count: $count, hskLevel: $hskLevel) {
      id
      hanzi
      pinyin
      meanings
      hskLevel
    }
  }",
  "variables": {
    "count": 5,
    "hskLevel": 1
  }
}

{
  "query": "mutation AddWord($input: WordInput!) {\n    addWord(input: $input) {\n      id\n      hanzi\n      traditional\n      pinyin\n      meanings\n      hskLevel\n      frequency\n    }\n  }",
  "variables": {
    "input": {
      "hanzi": "你好",
      "traditional": "你好",
      "pinyin": "nǐ hǎo",
      "meanings": ["hello", "hi"],
      "hskLevel": 1,
      "frequency": 100
    }
  }
}

{
  "query": "mutation AddWord($input: WordInput!) {\n    addWord(input: $input) {\n      id\n      hanzi\n      pinyin\n      meanings\n      hskLevel\n    }\n  }",
  "variables": {
    "input": {
      "hanzi": "好",
      "pinyin": "hǎo",
      "meanings": ["good", "well", "fine"],
      "hskLevel": 1,
      "frequency": 95
    }
  }
}

{
  "query": "mutation AddRelation($input: RelationInput!) {\n    addRelation(input: $input)\n  }",
  "variables": {
    "input": {
      "sourceId": "word1",
      "targetId": "word2",
      "type": "COMPOUND",
      "meaning": "forms compound word",
      "phrase": "好看",
      "pinyin": "hǎo kàn",
      "usageExample": "这个很好看 (This is very beautiful)"
    }
  }
}

{
  "query": "mutation UpdateWord($id: ID!, $input: WordInput!) {\n    updateWord(id: $id, input: $input) {\n      id\n      hanzi\n      pinyin\n      meanings\n      hskLevel\n    }\n  }",
  "variables": {
    "id": "word_id_here",
    "input": {
      "hanzi": "好",
      "pinyin": "hǎo",
      "meanings": ["good", "well", "fine", "okay"],
      "hskLevel": 1,
      "frequency": 98
    }
  }
}

{
  "query": "query GetLearningStats($wordId: ID!) {
    learningStats(wordId: $wordId) {
      wordId
      timesReviewed
      correctCount
      lastReviewed
      strength
    }
  }",
  "variables": {
    "wordId": "word_id_here"
  }
}

{
  "query": "mutation MarkReviewed($wordId: ID!, $correct: Boolean!) {
    markReviewed(wordId: $wordId, correct: $correct) {
      wordId
      timesReviewed
      correctCount
      strength
      lastReviewed
    }
  }",
  "variables": {
    "wordId": "word_id_here",
    "correct": true
  }
}
